import{_ as a,c as n,o as e,ag as p}from"./chunks/framework.QPV3Ar9-.js";const i="/assets/agent0.CfOi1y0_.png",l="/assets/agent1.B3mvgfB2.png",t="/assets/agent2.DH-1h9GP.png",c="/assets/agent3.CBfCJ_DV.png",o="/assets/agent4.BEG_w41m.png",r="/assets/agent7.BQIWOUed.jpeg",d="/assets/agent5.K3I0SIuf.png",m="/assets/agent6.Hj3aLwzs.png",g="/assets/gpu1.BqYtvfhm.jpeg",u="/assets/gpu2.Ctk8v8IU.jpeg",b="/assets/gpu3.DsMLQ_4f.jpg",U=JSON.parse('{"title":"自定义","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/oneclickvirt/oneclickvirt_custom.md","filePath":"guide/oneclickvirt/oneclickvirt_custom.md","lastUpdated":1779075993000}'),_={name:"guide/oneclickvirt/oneclickvirt_custom.md"};function h(P,s,v,k,f,I){return e(),n("div",null,s[0]||(s[0]=[p('<h1 id="自定义" tabindex="-1">自定义 <a class="header-anchor" href="#自定义" aria-label="Permalink to &quot;自定义&quot;">​</a></h1><h2 id="使用agent模式纳管无独立公网ipv4地址的节点" tabindex="-1">使用agent模式纳管无独立公网IPV4地址的节点 <a class="header-anchor" href="#使用agent模式纳管无独立公网ipv4地址的节点" aria-label="Permalink to &quot;使用agent模式纳管无独立公网IPV4地址的节点&quot;">​</a></h2><p>对于一些本地设备，节点虽然有IPV4公网访问权限，但是没有固定/动态的独立IPV4地址，无法直接使用标准模式通过SSH纳管节点，这里提供一种新的方式进行纳管----agent模式。</p><p><img src="'+i+'" alt="" loading="lazy"></p><p>新增节点点击对应的模式后，进入基础信息页面</p><p><img src="'+l+'" alt="" loading="lazy"></p><p>和常规的标准模式录入不一样，IP地址和端口不再是必填项，如果不填写也可以纳管。对于本地节点，不要填写这两个框；对于云服务器等有固定的IPV4的节点，可以填写。不填写留空的仅支持后续的<code>网络模式</code>选择<code>无端口映射模式</code>，而填写不留空的<code>网络模式</code>和正常标准模式一样可以选择所有的类型。</p><p><img src="'+t+'" alt="" loading="lazy"></p><p>点击保存后，可以在<code>连接配置</code>这块看到具体的生成命令的按钮，一经保存该节点token会写死，如果需要更新token，需要删除节点后重新新增节点，一切配置都得重新填写了，所以不要泄露token，否则很麻烦。</p><p><img src="'+c+'" alt="" loading="lazy"></p><p>点击生成后如图，直接复制对应的命令到本地的节点服务器上执行即可纳管，执行安装完毕后，可在当前页面下方的检测按钮上进行检测。</p><p><img src="'+o+'" alt="" loading="lazy"></p><p><img src="'+r+'" alt="" loading="lazy"></p><p>点击检测成功后，后续的相关配置页面按照原先的标准模式的说明来即可，没有什么不同。</p><p><img src="'+d+'" alt="" loading="lazy"></p><p>只有这块对于本地节点有所不同，需要选择<code>无端口映射</code>类型，方便后续手动通过管理员的<code>端口管理</code>页面进行<code>手动添加端口</code>操作，内穿端口到主控的IPV4地址上进行使用。</p><p><img src="'+m+`" alt="" loading="lazy"></p><p>手动添加端口映射时选择<code>控制端转发（内网穿透）</code>即可，非必要填写的项目可以留空不填，自动会筛选主控的端口进行映射的。</p><p>但这样有一个限制，务必要确保<code>主控面板</code>的部署方式是<code>脚本部署</code>或者本地编译部署的，不支持docker或docker compose部署方式，不支持非<code>Linux系统</code>的部署，因为主控部署的时候需要确保拥有对于主控部署的服务器的防火墙的操控权，所以也<code>需要root环境</code>下部署。</p><p><code>内穿端口</code>这项功能<code>仅限使用agent模式</code>纳管的节点，通过wss转发代理的方式进行，所以部署的时候，务必确保反代端口时按照说明有反代ws/wss协议，不要自行反代忘记了这点。</p><p>同时如果主控有更新了版本，务必确保节点侧也进行对应的更新，点击编辑节点后进入<code>连接配置</code>页面点击重新生成命令，重新安装一遍就行了。</p><h2 id="使用lxd-incus开设共享gpu设备的容器" tabindex="-1">使用LXD/INCUS开设共享GPU设备的容器 <a class="header-anchor" href="#使用lxd-incus开设共享gpu设备的容器" aria-label="Permalink to &quot;使用LXD/INCUS开设共享GPU设备的容器&quot;">​</a></h2><p>对于需要共享GPU设备的节点，务必确保纳管节点前节点本身已安装号对应的显卡驱动，且该显卡本身的命令执行无误，比如</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>要确保显示类似</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root@a12-ThinkStation-P620:/root/sharefile# nvidia-smi</span></span>
<span class="line"><span>Sat May 16 20:23:07 2026       </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| NVIDIA-SMI 535.171.04             Driver Version: 535.171.04   CUDA Version: 12.2     |</span></span>
<span class="line"><span>|-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>| GPU  Name                 Persistence-M | Bus-Id        Disp.A | Volatile Uncorr. ECC |</span></span>
<span class="line"><span>| Fan  Temp   Perf          Pwr:Usage/Cap |         Memory-Usage | GPU-Util  Compute M. |</span></span>
<span class="line"><span>|                                         |                      |               MIG M. |</span></span>
<span class="line"><span>|=========================================+======================+======================|</span></span>
<span class="line"><span>|   0  NVIDIA RTX A6000               Off | 00000000:61:00.0 Off |                  Off |</span></span>
<span class="line"><span>| 30%   42C    P0              83W / 300W |      0MiB / 49140MiB |      1%      Default |</span></span>
<span class="line"><span>|                                         |                      |                  N/A |</span></span>
<span class="line"><span>+-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>                                                                                         </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| Processes:                                                                            |</span></span>
<span class="line"><span>|  GPU   GI   CI        PID   Type   Process name                            GPU Memory |</span></span>
<span class="line"><span>|        ID   ID                                                             Usage      |</span></span>
<span class="line"><span>|=======================================================================================|</span></span>
<span class="line"><span>|  No running processes found                                                           |</span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>只有宿主机安装好了驱动才能进行容器化共享GPU资源。</p><p>然后需要通过本教程中的Incus/Lxd的教程，进行好本地环境的安装，安装完毕后，通过主控的agent模式纳管完毕且执行健康检测无误后，才进行后续的操作。</p><p>推荐开启节点仅兑换码兑换模式，通过管理员的兑换码页面选择GPU设备创建容器。</p><p><img src="`+g+'" alt="" loading="lazy"></p><p>创建成功后，切换为管理员的普通用户视图兑换掉，然后回到管理员视图，去端口管理页面进行容器的端口内穿，方便直接通过web的ssh进行连接配置。</p><p><img src="'+u+'" alt="" loading="lazy"></p><p>添加成功后，可以直接通过web的ssh进行连接操控本地的这个新容器了。</p><p>进入容器后，需要安装对应的和外部宿主机一样的驱动版本，只不过这次安装的时候，要确保不要加载进入内核，添加命令参数<code>--no-kernel-module</code>。</p><p>具体如何找驱动安装驱动，详见 <a href="https://www.spiritysdx.top/20240513/#%E5%AE%B9%E5%99%A8%E5%86%85%E5%AE%89%E8%A3%85gpu%E9%A9%B1%E5%8A%A8" target="_blank" rel="noreferrer">https://www.spiritysdx.top/20240513/#容器内安装gpu驱动</a> 如何进行的驱动安装。</p><p>安装完毕后，容器内也可以执行<code>nvidia-smi</code>得到输出，证明GPU已共享使用了。</p><p><img src="'+b+'" alt="" loading="lazy"></p><p>那此时就可以停止这个容器，以此为母本，使用兑换码的批量开设容器的复制模式，设置此容器为源容器进行复制开设新容器了。</p>',38)]))}const C=a(_,[["render",h]]);export{U as __pageData,C as default};
